(window.webpackJsonp=window.webpackJsonp||[]).push([[128],{755:function(n,t){n.exports='\x3c!-- \ntitle: 11-Linux杂\nsort: \n--\x3e \n\n## Curl\n\n发送网络请求\n\n```bash\ncurl https://www.baidu.com/\n# 下载\ncurl https://www.baidu.com/ -o 1.html\n# 静音模式，不输出任何东西\ncurl https://www.baidu.com/ -s \n# 指定请求头\ncurl -H -d -X\n# 设置头、post方法以及date\ncurl https://www.baidu.com/?name ==\'kiki\' -H "A:B" -X POST -d "age = 22"\n```\n\n## 后台执行\n\n```\n ./test &\n ./test >> out.txt 2>&1 &    # 将标准输出重定向到out.txt\n jobs -l     # 查看后台程序\n nohup ./test &  # 不挂起\n```\n\n## 信息\n\n```\nfree -h     # 内存信息\nps -ef | grep python3\nlsb_release -a\n```\n\n## wget\n\n```bash\nwget -c -r -np -k -L -p url\t# 下载全部文件\nwget -m url\t\t# 站点镜像\n```\n\n### 定时执行\n\n> `cron`\n\n```\n*    *    *    *    *\t<command>\n-    -    -    -    -\n|    |    |    |    |\n|    |    |    |    +----- 星期中星期几 (0 - 7) (星期天 为0)\n|    |    |    +---------- 月份 (1 - 12) \n|    |    +--------------- 一个月中的第几天 (1 - 31)\n|    +-------------------- 小时 (0 - 23)\n+------------------------- 分钟 (0 - 59)\n```\n\n### 彻底卸载\n\n```\napt-get remove --purge\n```\n\n### 内核\n\n```bash\n# 正在使用的内核\nuname -a\n# 全部内核\nrpm -qa | grep kernel\n# 卸载\nyum remove kernel-x.xx.x\n```\n\n'}}]);